 1	import { type Dispatch, type FC, type SetStateAction, useState } from 'react';
 2	import { useModal } from 'src/modules/Providers/modals/ModalHOC/useModal';
 3	
 4	import { ActionGroup, Button, ButtonVariant, Modal, ModalVariant } from '@patternfly/react-core';
 5	import { useForkliftTranslation } from '@utils/i18n';
 6	
 7	import { useIDEntities } from './hooks/useIDEntities';
 8	import type { AffinityLabel, AffinityRowData } from './utils/types';
 9	import AffinityForm from './AffinityForm';
10	
11	type AffinityEditModalProps = {
12	  focusedAffinity: AffinityRowData;
13	  onCancel: () => void;
14	  onSubmit: (affinity: AffinityRowData) => void;
15	  setFocusedAffinity: Dispatch<SetStateAction<AffinityRowData>>;
16	  title: string;
17	};
18	
19	const AffinityEditModal: FC<AffinityEditModalProps> = ({
20	  focusedAffinity,
21	  onCancel,
22	  onSubmit,
23	  setFocusedAffinity,
24	  title,
25	}) => {
26	  const { t } = useForkliftTranslation();
27	
28	  const { toggleModal } = useModal();
29	
30	  const [isDisabled, setIsDisabled] = useState(false);
31	  const expressions = useIDEntities<AffinityLabel>(focusedAffinity?.expressions ?? []);
32	  const fields = useIDEntities<AffinityLabel>(focusedAffinity?.fields ?? []);
33	
34	  return (
35	    <Modal
36	      data-testid="affinity-edit-modal"
37	      footer={
38	        <ActionGroup>
39	          <Button
40	            data-testid="save-affinity-rule-button"
41	            onClick={() => {
42	              onSubmit({
43	                ...focusedAffinity,
44	                expressions: expressions?.entities,
45	                fields: fields?.entities,
46	              });
47	            }}
48	            isDisabled={isDisabled}
49	            variant={ButtonVariant.primary}
50	          >
51	            {t('Save affinity rule')}
52	          </Button>
53	          <Button
54	            data-testid="cancel-affinity-rule-button"
55	            onClick={onCancel}
56	            size="sm"
57	            variant={ButtonVariant.link}
58	          >
59	            {t('Cancel')}
60	          </Button>
61	        </ActionGroup>
62	      }
63	      className="ocs-modal co-catalog-page__overlay"
64	      isOpen
65	      onClose={toggleModal}
66	      position="top"
67	      title={title}
68	      variant={ModalVariant.medium}
69	    >
70	      <AffinityForm
71	        expressions={expressions}
72	        fields={fields}
73	        focusedAffinity={focusedAffinity}
74	        setFocusedAffinity={setFocusedAffinity}
75	        setSubmitDisabled={setIsDisabled}
76	      />
77	    </Modal>
78	  );
79	};
80	
81	export default AffinityEditModal;

